以下是基于鲸鱼优化算法的机器人路径规划的Matlab代码：

```matlab
% 设置参数
N = 40; % 鲸鱼的数量
Max_iter = 100; % 最大迭代次数
a = 2; % 控制鲸鱼游动速度参数
b = 0.2; % 控制鲸鱼追踪最优解的速度参数
c = 1; % 控制鲸鱼位置更新的速度参数
dim = 2; % 二维平面

% 创建障碍物位置
obstacles = [2, 5; 3, 8; 6, 4; 9, 7];

% 创建起点和终点
start_point = [1, 1];
end_point = [10, 10];

% 创建鲸鱼的初始位置
whales = zeros(N, dim);
for i = 1:N
    whales(i, :) = [rand(1)*10, rand(1)*10];
end

% 初始化鲸鱼最优适应度和最优位置
best_fitness = Inf;
best_position = zeros(1, dim);

fitness_history = zeros(Max_iter, 1);

% 开始迭代
for iter = 1:Max_iter
    % 计算适应度值
    fitness_values = zeros(N, 1);
    for i = 1:N
        fitness_values(i) = fitness(whales(i, :), obstacles, start_point, end_point);

        % 更新最优适应度和最优位置
        if fitness_values(i) < best_fitness
            best_fitness = fitness_values(i);
            best_position = whales(i, :);
        end
    end

    % 绘制路径规划适应度变化图
    fitness_history(iter) = best_fitness;
    plot(1:iter, fitness_history(1:iter));
    title('Fitness History');
    xlabel('Iteration');
    ylabel('Fitness');

    % 绘制路径规划最优轨迹路线图
    x = [start_point(1), best_position(1), end_point(1)];
    y = [start_point(2), best_position(2), end_point(2)];

    figure;
    plot(obstacles(:, 1), obstacles(:, 2), 'ro');
    hold on;
    plot(x, y, 'b-', 'LineWidth', 2);
    plot(best_position(1), best_position(2), 'bo', 'MarkerSize', 10, 'MarkerFaceColor', 'b');
    plot(start_point(1), start_point(2), 'go', 'MarkerSize', 10, 'MarkerFaceColor', 'g');
    plot(end_point(1), end_point(2), 'ro', 'MarkerSize', 10, 'MarkerFaceColor', 'r');
    axis equal;
    title('Optimal Path');
    legend('Obstacles', 'Path', 'Best Position', 'Start Point', 'End Point');

    % 更新鲸鱼位置
    for i = 1:N
        d = abs(whales(i, :) - best_position);
        whales(i, :) = whales(i, :) + a * rand(1, dim) .* sign(rand(1, dim) - 0.5) + b * rand(1, dim) .* d  + c * rand(1, dim) .* (best_position - whales(i, :));

        % 限制鲸鱼位置在地图范围内
        whales(i, :) = max(whales(i, :), [0 0]);
        whales(i, :) = min(whales(i, :), [10 10]);
    end
end

% 计算适应度函数
function fitness_value = fitness(position, obstacles, start_point, end_point)
    fitness_value = norm(position - end_point);

    % 判断路径是否经过障碍物
    for i = 1:size(obstacles, 1)
        if isIntersect(start_point, position, obstacles(i, :))
            fitness_value = fitness_value + norm(position - obstacles(i, :));
        end

        if isIntersect(position, end_point, obstacles(i, :))
            fitness_value = fitness_value + norm(position - obstacles(i, :));
        end
    end
end

% 判断路径是否与障碍物相交
function intersect = isIntersect(p1, p2, obstacle)
    d1 = norm(p1 - obstacle);
    d2 = norm(p2 - obstacle);
    if d2 < d1
        temp = p1;
        p1 = p2;
        p2 = temp;
    end

    t = linspace(0, 1, 100);
    x = p1(1) + t .* (p2(1) - p1(1));
    y = p1(2) + t .* (p2(2) - p1(2));

    intersect = false;
    for i = 1:length(x)
        if norm([x(i), y(i)] - obstacle) < 0.5
            intersect = true;
            break;
        end
    end
end
